import{_ as e,o as a,c as n,a2 as s}from"./chunks/framework.CMAFtOGK.js";const u=JSON.parse('{"title":"作文模板与高分句型","description":"公共英语 · 作文模板与高分句型","frontmatter":{"title":"作文模板与高分句型","description":"公共英语 · 作文模板与高分句型","category":"english-note"},"headers":[],"relativePath":"posts/english/notes/writing.md","filePath":"posts/english/notes/writing.md","lastUpdated":1784747786000}'),l={name:"posts/english/notes/writing.md"};function i(r,t,o,p,d,c){return a(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="✍️-作文模板与高分句型" tabindex="-1">✍️ 作文模板与高分句型 <a class="header-anchor" href="#✍️-作文模板与高分句型" aria-label="Permalink to &quot;✍️ 作文模板与高分句型&quot;">​</a></h1><blockquote><p>广东普通专升本《公共英语》写作 | 应用文主攻 | 约 100 词</p></blockquote><hr><h2 id="一、基础信息-广东专升本" tabindex="-1">一、基础信息（广东专升本） <a class="header-anchor" href="#一、基础信息-广东专升本" aria-label="Permalink to &quot;一、基础信息（广东专升本）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">要求</th></tr></thead><tbody><tr><td style="text-align:left;">字数</td><td style="text-align:left;"><strong>约 100 词</strong>（建议实写 90–110）</td></tr><tr><td style="text-align:left;">建议用时</td><td style="text-align:left;"><strong>25–30 分钟</strong></td></tr><tr><td style="text-align:left;">满分</td><td style="text-align:left;"><strong>15 分</strong></td></tr><tr><td style="text-align:left;">体裁优先级</td><td style="text-align:left;"><strong>书信 &gt; 通知 &gt; 其它应用文</strong> ≫ 议论文/图表（广东极少）</td></tr><tr><td style="text-align:left;">评分侧重</td><td style="text-align:left;">格式正确 + 要点写全 + 语言通顺 + 结构清楚</td></tr><tr><td style="text-align:left;">署名</td><td style="text-align:left;">题目未指定时用 <strong>Li Hua</strong>（切勿写真名）</td></tr></tbody></table><p><strong>考场提醒：</strong></p><ol><li>先把提示要点勾完，再套模板——漏一点就掉内容分</li><li>少堆空话（<code>Taking all these factors...</code> 之类），把字数留给时间/地点/内容</li><li>写完 30 秒检查：称呼、落款、时态、拼写、要点是否全</li></ol><hr><h2 id="二、必背模板-按你的原版保留-略作格式整理" tabindex="-1">二、必背模板（按你的原版保留，略作格式整理） <a class="header-anchor" href="#二、必背模板-按你的原版保留-略作格式整理" aria-label="Permalink to &quot;二、必背模板（按你的原版保留，略作格式整理）&quot;">​</a></h2><h3 id="📌-模板-a-万能书信-主背-★★★★★" tabindex="-1">📌 模板 A：万能书信（主背 ★★★★★） <a class="header-anchor" href="#📌-模板-a-万能书信-主背-★★★★★" aria-label="Permalink to &quot;📌 模板 A：万能书信（主背 ★★★★★）&quot;">​</a></h3><p><strong>适用：</strong> 邀请 / 申请 / 感谢 / 道歉 / 建议 / 推荐 / 投诉等</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dear _________ , (收信人，题目未指定则写 Mr. Smith 或 Mark)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>How is everything going? I am writing this letter to express my earnest hope to / recommend _________(填入写信目的，如：invite you to our speech contest / apply for the position of English tutor).</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Here are some relevant details about this matter.(万能过渡句)First and foremost, _________(填入细节一：如 the deadline is Nov. 10th).Furthermore, _________(填入细节二：如 it is highly beneficial to us).Last but not least, _________(填入细节三或升华句：如 it will be a meaningful and unforgettable experience).</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Taking all these factors into consideration, I sincerely hope you can _________(填入期许，如：accept my invitation / give me an opportunity).I would be highly appreciative if you could take my request into consideration.I am looking forward to hearing from you soon.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Yours sincerely,</span></span>
<span class="line"><span>Li Hua</span></span>
<span class="line"><span>(注意：千万不要写自己的真实姓名)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h4 id="书信范文-邀请" tabindex="-1">书信范文（邀请） <a class="header-anchor" href="#书信范文-邀请" aria-label="Permalink to &quot;书信范文（邀请）&quot;">​</a></h4><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dear Peter,</span></span>
<span class="line"><span>How is everything going? I am writing this letter to express my earnest hope to invite you to visit the exhibition of Traditional Chinese Culture in our school, and I would like to highly recommend a special activity to you.</span></span>
<span class="line"><span>Here are some relevant details about this matter. First and foremost, the exhibition will be held next Friday. Furthermore, you can experience the art of paper-cutting yourself. Last but not least, it will be a meaningful and unforgettable experience.</span></span>
<span class="line"><span>Taking all these factors into consideration, I sincerely hope you can accept my invitation. I would be highly appreciative if you could take my request into consideration. I am looking forward to hearing from you soon.</span></span>
<span class="line"><span>Yours sincerely,</span></span>
<span class="line"><span>Li Hua</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><blockquote><p><strong>字数自检：</strong> 范文约 100 词量级；若提示里有具体时间/地点，优先补进 First / Furthermore 两句，比堆“meaningful”更稳。</p></blockquote><hr><h3 id="📌-模板-b-notice-通知-主背-★★★★★" tabindex="-1">📌 模板 B：NOTICE 通知（主背 ★★★★★） <a class="header-anchor" href="#📌-模板-b-notice-通知-主背-★★★★★" aria-label="Permalink to &quot;📌 模板 B：NOTICE 通知（主背 ★★★★★）&quot;">​</a></h3><p><strong>适用场景：</strong> 学校、学生会或俱乐部发布活动通知，如音乐周、运动会、英语演讲比赛等。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(正中间大写) NOTICE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>May I have your attention, please? To enrich our campus life, our school is going to organize _________(填入活动名称，如 a music week).</span></span>
<span class="line"><span></span></span>
<span class="line"><span>The event is scheduled to be held in _________(填入地点，如 the school hall)at _________(填入时间，如 2:00 p.m. next Friday).There are many exciting activities waiting for you.(万能凑字句)For one thing, _________(细节一：如 you can enjoy pop music).For another, _________(细节二：如 please bring your own instruments).</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Those who are interested in it are highly welcome to participate.(高级句型：极其欢迎感兴趣的同学参加)If you have any questions, please feel free to contact us at 1234567.(万能结尾句)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(右下角发通知的组织，如) The Student Union</span></span>
<span class="line"><span>(右下角发通知的日期，如) Nov. 10th</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p><strong>格式要点：</strong></p><ul><li>标题 <code>NOTICE</code> 居中大写</li><li>正文写清：活动名 / 时间 / 地点 / 内容 / 欢迎参加 / 联系方式</li><li>右下角：组织 + 日期</li></ul><hr><h3 id="📌-模板-c-图表-社会现象-拓展-广东极少考" tabindex="-1">📌 模板 C：图表 / 社会现象（拓展，广东极少考） <a class="header-anchor" href="#📌-模板-c-图表-社会现象-拓展-广东极少考" aria-label="Permalink to &quot;📌 模板 C：图表 / 社会现象（拓展，广东极少考）&quot;">​</a></h3><p><strong>适用场景：</strong> 描述社会热点趋势或图表数据，如大学生沉迷手机、网购的流行、低碳出行等。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>As is clearly shown in the chart / As we can see in our daily life, the past few years have witnessed a dramatic change in _________(填入现象主题，如 using mobile phones / online shopping).Specifically, this trend is becoming increasingly popular among people.(万能现象补充句)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>There are several reasons behind this phenomenon.(引出原因过渡句)First and foremost, _________(填入原因一：如 it is very convenient).Furthermore, _________(填入原因二：如 it saves us a lot of time / we can chat with friends anytime and anywhere).</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Taking all these factors into consideration, we can naturally draw the conclusion that _________(填入趋势预测，如：this trend will continue).In my opinion, we should take a rational attitude towards it.(万能高分结尾呼吁：在我看来，我们应该对此采取理性的态度)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><blockquote><p>⚠️ <strong>备考优先级：低。</strong> 广东统招公共英语写作主考应用文；本模板仅作备用，冲刺阶段别占主背时间。</p></blockquote><hr><h3 id="📌-模板-d-正反观点-建议类议论文-拓展-广东极少考" tabindex="-1">📌 模板 D：正反观点 / 建议类议论文（拓展，广东极少考） <a class="header-anchor" href="#📌-模板-d-正反观点-建议类议论文-拓展-广东极少考" aria-label="Permalink to &quot;📌 模板 D：正反观点 / 建议类议论文（拓展，广东极少考）&quot;">​</a></h3><p><strong>适用场景：</strong> 给出两个对立观点让你选择，或者提出一个问题让你给出建议。如：团队合作 vs 独立工作、在校外租房 vs 住校内。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Nowadays, there is a heated debate over _________(填入讨论的话题，如 whether students should work part-time).Opinions vary from person to person.(万能开场：如今关于...有激烈的讨论，人们的观点因人而异)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>On the one hand, some people argue that _________(填入甲方观点：如 working part-time is beneficial).They believe that _________(解释甲方观点：如 it provides practical experience).On the other hand, others hold the opposite view.(转折句：另一方面，其他人持有相反观点)They point out that _________(填入乙方观点：如 it takes up too much study time).</span></span>
<span class="line"><span></span></span>
<span class="line"><span>As far as I am concerned, I am in favor of the former/latter opinion.(表明立场：就我而言，我赞同前者/后者的观点)The reason is that _________(给出自己的理由：如 practical skills are equally important for our future career).Therefore, we should find a proper balance.(万能结尾：因此，我们应该找到一个合适的平衡点)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><blockquote><p>⚠️ <strong>备考优先级：低。</strong> 同上，主背书信 + 通知即可。</p></blockquote><hr><h2 id="三、高频写信目的开头-替换壳-提分用" tabindex="-1">三、高频写信目的开头（替换壳，提分用） <a class="header-anchor" href="#三、高频写信目的开头-替换壳-提分用" aria-label="Permalink to &quot;三、高频写信目的开头（替换壳，提分用）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">功能</th><th style="text-align:left;">开头句</th></tr></thead><tbody><tr><td style="text-align:left;">邀请</td><td style="text-align:left;">I am writing to invite you to...</td></tr><tr><td style="text-align:left;">申请</td><td style="text-align:left;">I am writing to apply for the position of...</td></tr><tr><td style="text-align:left;">感谢</td><td style="text-align:left;">I am writing to express my sincere thanks for...</td></tr><tr><td style="text-align:left;">道歉</td><td style="text-align:left;">I am writing to apologize for...</td></tr><tr><td style="text-align:left;">建议</td><td style="text-align:left;">I am writing to offer some suggestions on...</td></tr><tr><td style="text-align:left;">推荐</td><td style="text-align:left;">I am writing to recommend... to you.</td></tr><tr><td style="text-align:left;">投诉</td><td style="text-align:left;">I am writing to complain about...</td></tr><tr><td style="text-align:left;">通知目的</td><td style="text-align:left;">To enrich our campus life, ... is going to be held.</td></tr><tr><td style="text-align:left;">欢迎参加</td><td style="text-align:left;">Those who are interested are highly welcome to participate.</td></tr><tr><td style="text-align:left;">期盼</td><td style="text-align:left;">I am looking forward to hearing from you soon. / I am looking forward to your early reply.</td></tr></tbody></table><hr><h2 id="四、高分小替换-点缀即可-别堆" tabindex="-1">四、高分小替换（点缀即可，别堆） <a class="header-anchor" href="#四、高分小替换-点缀即可-别堆" aria-label="Permalink to &quot;四、高分小替换（点缀即可，别堆）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">低分词</th><th style="text-align:left;">可换</th></tr></thead><tbody><tr><td style="text-align:left;">important</td><td style="text-align:left;">crucial / vital / significant / essential</td></tr><tr><td style="text-align:left;">good</td><td style="text-align:left;">beneficial / positive</td></tr><tr><td style="text-align:left;">bad</td><td style="text-align:left;">harmful / negative</td></tr><tr><td style="text-align:left;">many</td><td style="text-align:left;">a large number of / various</td></tr><tr><td style="text-align:left;">more and more</td><td style="text-align:left;">increasingly / a growing number of</td></tr><tr><td style="text-align:left;">think</td><td style="text-align:left;">believe / hold / argue</td></tr><tr><td style="text-align:left;">so</td><td style="text-align:left;">therefore / as a result</td></tr><tr><td style="text-align:left;">solve</td><td style="text-align:left;">address / deal with</td></tr></tbody></table><h3 id="常用连接" tabindex="-1">常用连接 <a class="header-anchor" href="#常用连接" aria-label="Permalink to &quot;常用连接&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">功能</th><th style="text-align:left;">词</th></tr></thead><tbody><tr><td style="text-align:left;">顺承</td><td style="text-align:left;">First and foremost / First of all / Furthermore / Last but not least</td></tr><tr><td style="text-align:left;">因果</td><td style="text-align:left;">Therefore / As a result / Thus</td></tr><tr><td style="text-align:left;">举例</td><td style="text-align:left;">For one thing... For another... / For example</td></tr><tr><td style="text-align:left;">总结</td><td style="text-align:left;">Taking all these factors into consideration / In conclusion</td></tr></tbody></table><hr><h2 id="五、写作流程-约-100-词" tabindex="-1">五、写作流程（约 100 词） <a class="header-anchor" href="#五、写作流程-约-100-词" aria-label="Permalink to &quot;五、写作流程（约 100 词）&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Step 1: 审题（2 分钟）——体裁、收信人/组织、要点清单</span></span>
<span class="line"><span>Step 2: 列点（2 分钟）——目的 1 句 + 细节 2–3 点 + 期许 1 句</span></span>
<span class="line"><span>Step 3: 套写（15–18 分钟）——直接填模板</span></span>
<span class="line"><span>Step 4: 检查（3–5 分钟）——格式 / 要点 / 时态 / 拼写 / 字数</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><hr><h2 id="秒杀口诀" tabindex="-1">秒杀口诀 <a class="header-anchor" href="#秒杀口诀" aria-label="Permalink to &quot;秒杀口诀&quot;">​</a></h2><blockquote><p><strong>广东作文约百词，书信通知最对口</strong><br><strong>要点写全格式对，套话少用细节够</strong><br><strong>署名只用 Li Hua，写完检查不扣分</strong></p></blockquote><hr><h2 id="相关笔记" tabindex="-1">相关笔记 <a class="header-anchor" href="#相关笔记" aria-label="Permalink to &quot;相关笔记&quot;">​</a></h2><ul><li><a href="/zhuan-sheng-ben-notes/posts/english/notes/overview">专升本英语考试概述与题型分析</a></li><li><a href="/zhuan-sheng-ben-notes/guide/sources">历年真题分类与讲解</a></li><li>高频词汇速记</li><li>英语知识库</li></ul>`,48)])])}const g=e(l,[["render",i]]);export{u as __pageData,g as default};
